body.raw:
SELECT Id, TransactionId, Amount, OrderId, TimeStamp
FROM [Payments].[Payments]
WHERE TransactionId = '{{lastTransactionId}}';
-- Expect Amount = {{lastAmount}}

exec:
let sql = "SELECT Id, TransactionId, Amount, OrderId, TimeStamp
FROM [Payments].[Payments]
WHERE TransactionId = '{id}';
-- Expect Amount = {amount}";

let sql = "SELECT Id, TransactionId, Amount, PaymentTypeMethod, OrderId, TimeStamp
FROM [Payments].[Payments]
WHERE TransactionId = '{id}';
-- Expect PaymentTypeMethod = 2 (token) or 1 (Pay Page)";

let sql = "SELECT r.Id, r.TransactionId, r.Amount, r.OrderId, r.OriginalPaymentId, r.TimeStamp
FROM [Payments].[Refunds] r
INNER JOIN [Payments].[Payments] p ON p.Id = r.OriginalPaymentId
WHERE p.TransactionId = '{id}'
ORDER BY r.TimeStamp DESC;
-- Expect Amount = 10.00 (partial)";

let sql = "SELECT v.Id, v.TransactionId, v.OrderId, v.OriginalPaymentId, v.ResponseCode, v.ResponseMessage, v.TimeStamp
FROM [Payments].[Voids] v
INNER JOIN [Payments].[Payments] p ON p.Id = v.OriginalPaymentId
WHERE p.TransactionId = '{id}'
ORDER BY v.TimeStamp DESC;
-- Expect void row (no Amount column on Voids)";
